SET @s = IF((SELECT COUNT(*) FROM information_schema.TABLES WHERE TABLE_SCHEMA=DATABASE() AND TABLE_NAME='LlmCallLogs')=1 AND (SELECT COUNT(*) FROM information_schema.STATISTICS WHERE TABLE_SCHEMA=DATABASE() AND TABLE_NAME='LlmCallLogs' AND INDEX_NAME='IX_LlmCallLogs_MonitorTime')=0,'ALTER TABLE LlmCallLogs ADD INDEX IX_LlmCallLogs_MonitorTime (CreatedAt(32), ResponseStatusCode)','SELECT 1'); PREPARE q FROM @s; EXECUTE q; DEALLOCATE PREPARE q;
SET @s = IF((SELECT COUNT(*) FROM information_schema.TABLES WHERE TABLE_SCHEMA=DATABASE() AND TABLE_NAME='LlmCallLogs')=1 AND (SELECT COUNT(*) FROM information_schema.STATISTICS WHERE TABLE_SCHEMA=DATABASE() AND TABLE_NAME='LlmCallLogs' AND INDEX_NAME='IX_LlmCallLogs_MonitorFilter')=0,'ALTER TABLE LlmCallLogs ADD INDEX IX_LlmCallLogs_MonitorFilter (Provider(64), Model(128), CreatedAt(32))','SELECT 1'); PREPARE q FROM @s; EXECUTE q; DEALLOCATE PREPARE q;
